class Solution:
    def differenceOfDistinctValues(self, grid):
        m, n = len(grid), len(grid[0])
        diag = {}
        for r in range(m):
            for c in range(n):
                diag.setdefault(r - c, []).append((r, c, grid[r][c]))
        ans = [[0] * n for _ in range(m)]
        for cells in diag.values():
            cells.sort()
            for idx, (r, c, v) in enumerate(cells):
                before = set(x[2] for x in cells[:idx])
                after = set(x[2] for x in cells[idx + 1:])
                ans[r][c] = abs(len(before) - len(after))
        return ans

