var differenceOfDistinctValues = function(grid) {
    const m = grid.length;
    const n = grid[0].length;
    const ans = Array.from({ length: m }, () => new Array(n).fill(0));
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            const tl = new Set();
            let rr = r - 1, cc = c - 1;
            while (rr >= 0 && cc >= 0) {
                tl.add(grid[rr][cc]);
                rr -= 1;
                cc -= 1;
            }
            const br = new Set();
            rr = r + 1;
            cc = c + 1;
            while (rr < m && cc < n) {
                br.add(grid[rr][cc]);
                rr += 1;
                cc += 1;
            }
            ans[r][c] = Math.abs(tl.size - br.size);
        }
    }
    return ans;
};
